SELECT SUM(REPLACE(revenues, ',', '')) AS total_revenue
FROM financial_data
WHERE year_id = 1;

SELECT indicator_name
FROM financial_indicators
WHERE indicator_type = 'Growth';

SELECT year_name
FROM financial_years
WHERE year_name = '2022';

SELECT year_id, SUM(CAST(revenues AS REAL)) AS total_revenue
FROM financial_data
GROUP BY year_id;

SELECT year_name, COUNT(*) 
FROM financial_years 
GROUP BY year_name;

SELECT kpi_name, AVG(actual_value) AS average_actual_value
FROM kpis
GROUP BY kpi_name;

SELECT year_name, start_date
FROM financial_years
WHERE year_id = 1;

SELECT year_name, COUNT(year_id) AS total_occurrences
FROM financial_years
GROUP BY year_id;

SELECT SUM(CAST(REPLACE(value, ',', '') AS REAL)) AS total_revenue_growth_rate
FROM financial_indicators
WHERE indicator_name = 'Revenue Growth Rate';

SELECT revenues
FROM financial_data
WHERE CAST(revenues AS REAL) > 30000;
